suspend fun logSimpleWorkoutCreated(userId: String, workoutId: String, exerciseCount: Int, totalSets: Int): Result<Unit> {
  val params = bundleOf(
    "user_id" to userId,
    "workout_id" to workoutId,
    "exercise_count" to exerciseCount,
    "total_sets" to totalSets,
    "workout_type" to "simple"
  )
  return firebaseAnalytics.logEvent("simple_workout_created", params)
}

