@Test
fun `should reject workout with name too short`() {
  assertThatThrownBy {
    SimpleWorkout(
      id = SimpleWorkoutId.generate(),
      userId = "user123",
      name = "AB", // Too short
      description = null,
      exercises = emptyList(),
      createdAt = Instant.now(),
      updatedAt = Instant.now()
    )
  }.isInstanceOf(IllegalArgumentException::class.java)
   .hasMessageContaining("Name must be 3-100 characters")
}

