@Test
fun `should create and retrieve workout`() = runTest {
  // Arrange
  val workout = createTestSimpleWorkout()

  // Act
  val createResult = repository.createWorkout(workout)
  val retrieveResult = repository.getWorkoutById(workout.id.value)

  // Assert
  assertThat(createResult.isSuccess).isTrue()
  assertThat(retrieveResult.getOrNull()).isEqualTo(workout)
}

@Test
fun should_complete_workout_creation_end_to_end() {
  composeTestRule.setContent {
    LiftrixTheme {
      WorkoutScreen(user = testUser)
    }
  }

  // Tap create workout button
  composeTestRule.onNodeWithText("Create Your First Workout").performClick()

  // Fill workout details
  composeTestRule.onNodeWithText("Workout Name").performTextInput("Test Workout")
  composeTestRule.onNodeWithText("Next").performClick()

  // Add exercise
  composeTestRule.onNodeWithText("Add Exercise").performClick()
  composeTestRule.onNodeWithText("Exercise Name").performTextInput("Push-ups")

  // Complete creation
  composeTestRule.onNodeWithText("Save Workout").performClick()

  // Verify results screen
  composeTestRule.onNodeWithText("Workout Created Successfully!").assertIsDisplayed()
}

